targets.expr:
# Disk Time-to-Full Prediction (in days)
# Uses predict_linear to estimate when disk will be 100% full
(
  (
    node_filesystem_size_bytes{instance=~"$instance.*", mountpoint="/", fstype!="tmpfs"}
    - node_filesystem_avail_bytes{instance=~"$instance.*", mountpoint="/", fstype!="tmpfs"}
  )
  / node_filesystem_size_bytes{instance=~"$instance.*", mountpoint="/", fstype!="tmpfs"}
  -
  predict_linear(
    node_filesystem_avail_bytes{instance=~"$instance.*", mountpoint="/", fstype!="tmpfs"}[24h],
    86400
  ) / node_filesystem_size_bytes{instance=~"$instance.*", mountpoint="/", fstype!="tmpfs"}
) * -1 / (
  1 - (
    node_filesystem_size_bytes{instance=~"$instance.*", mountpoint="/", fstype!="tmpfs"}
    - node_filesystem_avail_bytes{instance=~"$instance.*", mountpoint="/", fstype!="tmpfs"}
  ) / node_filesystem_size_bytes{instance=~"$instance.*", mountpoint="/", fstype!="tmpfs"}
)

# Alternative simpler formula: Days until full based on linear prediction
(
  node_filesystem_avail_bytes{instance=~"$instance.*", mountpoint="/", fstype!="tmpfs"}
  / 
  clamp_min(
    -deriv(node_filesystem_avail_bytes{instance=~"$instance.*", mountpoint="/", fstype!="tmpfs"}[24h]),
    0.0001
  )
) / 86400
